						st.sel_ch = #srv.channels
						save_state()
						apply_selection()
						st.status = "Channel #" .. line
					end
				end
				st.prompt = nil
				return true
			end
			st.prompt = nil
			return true
		end

		load_state()
		default_servers()
		ensure_selection()

		local shell = appkit.shell({
			on_command = function(id)
