local MAX_LOG = 200
local _print = print
function print(...)
  local parts = {}
  for i = 1, select("#", ...) do parts[i] = tostring(select(i, ...)) end
  local line = table.concat(parts, "\t")
  _G.AtlasOS_log[#_G.AtlasOS_log + 1] = line
  while #_G.AtlasOS_log > MAX_LOG do table.remove(_G.AtlasOS_log, 1) end
  _print(...)
end

