      local line = " " .. clamp(it.label, box_w - 2)
      line = line .. string.rep(" ", math.max(0, box_w - #line))
      draw.text(cx0 + x0, cy0 + y0 + i, line:sub(1, box_w), self.dd_fg, self.dd_bg)
      self._dd_zones[#self._dd_zones + 1] = {
        x0 = x0,
        y0 = y0 + i,
        x1 = x0 + box_w - 1,
        y1 = y0 + i,
