end

function atlassettings.set_developer_mode(on)
  local t = read()
  t.developer_mode = not not on
  atlassettings.save(t)
  return t.developer_mode
end

function atlassettings.toggle_developer_mode()
  local t = read()
  t.developer_mode = not t.developer_mode
  atlassettings.save(t)
