function M.dispatch(ctx, tag)
	if not tag then return end
	local UI = ctx.UI
	local atlastheme = ctx.atlastheme
	local startmenu = ctx.startmenu
	local paths = ctx.paths
	if tag:sub(1, 4) == "cat:" then
