    d._focus = nil
    for j = 1, n do
      d._windows[j]:set_focused(false)
    end
    return
  end
  local fi = 1
  for j = 1, #vis do
    if vis[j] == d._focus then fi = j break end
  end
  local prev_w = vis[fi - 1]
  if not prev_w then prev_w = vis[#vis] end
  window.Desktop.set_focus(d, prev_w)
  window.Desktop.bring_to_front(d, prev_w)
end

--- Paint only a region (wallpaper + windows). Skips minimized windows.
function window.Desktop.paint_region(d, gx, gy, gw, gh)
  gx, gy = math.max(1, math.floor(gx)), math.max(1, math.floor(gy))
  gw, gh = math.max(1, math.floor(gw)), math.max(1, math.floor(gh))
  draw.fillRect(gx, gy, gw, gh, d.bg_bg)
  for i = 1, #d._windows do
    if not d._windows[i].minimized then
      d._windows[i]:paint()
    end
  end
end

function window.Desktop.paint(d, gw, gh)
  if not gw or not gh then
    local cw, ch = draw.canvas_cells()
    if cw and ch then
      gw, gh = cw, ch
    end
  end
  gw = gw or 80
  gh = gh or 24
  window.Desktop.paint_region(d, 1, 1, gw, gh)
end

return window
]=],
	},
}

local function atlas_bootstrap_loader()
  local orig_loadfile = rawget(_G, "loadfile")
  local orig_dofile = rawget(_G, "dofile")

  local function atlas_loadfile(path)
	path = tostring(path or "")
	if type(orig_loadfile) == "function" then
	  local ok, chunk, err = pcall(orig_loadfile, path)
	  if ok and (type(chunk) == "function" or chunk == nil) then
		return chunk, err
	  end
	end
	if fs and type(fs.read) == "function" and type(load) == "function" then
	  local ok, raw = pcall(fs.read, path)
	  if not ok or raw == nil then
		return nil, "could not read " .. tostring(path)
	  end
	  return load(raw, "@" .. path)
	end
	return nil, "no script loader available (loadfile/fs.read+load missing)"
  end

  local function atlas_dofile(path)
	local chunk, err = atlas_loadfile(path)
	if not chunk then
	  if type(orig_dofile) == "function" then
		return orig_dofile(path)
	  end
	  error(err)
	end
	return chunk()
  end

  _G.loadfile = atlas_loadfile
  _G.dofile = atlas_dofile
  _G.__AtlasLoad = atlas_dofile
  return atlas_dofile
end

atlas_bootstrap_loader()

local function normalize(path)
	path = tostring(path or "")
	path = path:gsub("\\", "/")
	path = path:gsub("/+", "/")
	if path == "" then return "/" end
	if #path > 1 and path:sub(-1) == "/" then path = path:sub(1, -2) end
	return path
end

local function ensure_parent_dir(path)
	path = normalize(path)
	local parent = path:match("^(.+)/[^/]+$")
	if not parent or parent == "" or parent == "/" then return true end
	local acc = ""
	for part in parent:gmatch("[^/]+") do
		acc = (acc == "") and ("/" .. part) or (acc .. "/" .. part)
		if fs.makeDir then
			local ok, err = pcall(fs.makeDir, acc)
			if not ok then return false, err end
		end
	end
	return true
end

local function read_file(path)
	local ok, raw = pcall(fs.read, normalize(path))
	if ok then return raw end
	return nil
end

local function write_file(path, body)
	local ok_dir, err_dir = ensure_parent_dir(path)
	if not ok_dir then return false, err_dir end
	local ok, err = pcall(fs.write, normalize(path), body)
	if not ok then return false, err end
	return true
end

local function verify_core_paths()
	local missing = {}
	for _, path in ipairs(CORE_PATHS) do
		if read_file(path) == nil then
			missing[#missing + 1] = path
		end
	end
	return missing
end

local function run_script(path)
	if type(_G.__AtlasLoad) == "function" then
		return _G.__AtlasLoad(path)
	end
	error("no script loader available (__AtlasLoad missing)")
end

local function format_error(err)
	if debug and type(debug.traceback) == "function" then
		return debug.traceback(tostring(err), 2)
	end
	return tostring(err)
end

local function looks_like_atlas_startup(body)
	body = tostring(body or "")
	return body:find("installer_gate.lua", 1, true)
		or body:find("boot_desktop.lua", 1, true)
		or body:find("AtlasOS", 1, true)
end

local function install_startup_hook()
	local prev = read_file(STARTUP_PATH)
	if prev and prev:gsub("%s", "") ~= "" and not prev:find(MARKER, 1, true) and not looks_like_atlas_startup(prev) then
		local ok_backup, err_backup = write_file(STARTUP_BACKUP, prev)
		if not ok_backup then
			return false, "could not write startup backup: " .. tostring(err_backup)
		end
		print("Backed up previous startup to " .. STARTUP_BACKUP)
	end
	local ok, err = write_file(STARTUP_PATH, NORMAL_STARTUP)
	if not ok then
		return false, "could not write startup hook: " .. tostring(err)
	end
	return true
end

local function write_bundle()
	local wrote, skipped = 0, 0
	for index, item in ipairs(BUNDLE) do
		local current = read_file(item.path)
		if current == item.body then
			skipped = skipped + 1
		else
			local ok, err = write_file(item.path, item.body)
			if not ok then
				return false, "failed to write " .. tostring(item.path) .. ": " .. tostring(err)
			end
			wrote = wrote + 1
		end
		if index == 1 or index == #BUNDLE or index % 10 == 0 then
			print(string.format("[%d/%d] %s", index, #BUNDLE, item.path))
		end
	end
	return true, wrote, skipped
end

local function main()
	print("AtlasOS web installer")
	print(string.format("Bundle: %d files, %d bytes", BUNDLE_FILE_COUNT, BUNDLE_TOTAL_BYTES))
	print("")

	local ok_bundle, wrote, skipped = write_bundle()
	if not ok_bundle then
		error(wrote)
	end
	print(string.format("Wrote %d file(s); %d already up to date.", wrote, skipped))

	local missing = verify_core_paths()
	if #missing > 0 then
		print("")
		for _, path in ipairs(missing) do
			print("Missing required file: " .. path)
		end
		error("bundle verification failed")
	end

	local ok_startup, startup_err = install_startup_hook()
	if not ok_startup then
		error(startup_err)
	end

	print("Startup hook installed at " .. STARTUP_PATH)
	print("Launching AtlasOS…")
	print("")
	run_script("/home/AtlasOS/installer_gate.lua")
end

local ok, err = xpcall(main, format_error)
if not ok then
	print("AtlasOS web install failed: " .. tostring(err))
end

